using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ---------------------------------------------------------------
    //  AddItem
    // ---------------------------------------------------------------

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 9.99m);

        Assert.AreEqual(9.99m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleQuantity_MultipliesPrice()
    {
        _cart.AddItem("SKU-001", quantity: 3, price: 5.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDifferentItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 2, price: 7.50m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantities()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 5.00m);
        _cart.AddItem("SKU-001", quantity: 2, price: 5.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_ZeroQuantity_Throws()
    {
        _cart.AddItem("SKU-001", quantity: 0, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativeQuantity_Throws()
    {
        _cart.AddItem("SKU-001", quantity: -1, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativePrice_Throws()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: -10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_Throws()
    {
        _cart.AddItem(null!, quantity: 1, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_EmptySku_Throws()
    {
        _cart.AddItem("", quantity: 1, price: 5.00m);
    }

    // ---------------------------------------------------------------
    //  RemoveItem
    // ---------------------------------------------------------------

    [TestMethod]
    public void RemoveItem_ExistingItem_DecreasesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalBecomesZero()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 8.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentItem_Throws()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void RemoveItem_NullSku_Throws()
    {
        _cart.RemoveItem(null!);
    }

    // ---------------------------------------------------------------
    //  CalculateTotal
    // ---------------------------------------------------------------

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 20.00m);
        _cart.AddItem("SKU-002", quantity: 3, price: 10.00m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_FractionalPrices_HandlesDecimalsCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 3, price: 1.33m);

        Assert.AreEqual(3.99m, _cart.CalculateTotal());
    }

    // ---------------------------------------------------------------
    //  ApplyCoupon
    // ---------------------------------------------------------------

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_NullCode_Throws()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_Throws()
    {
        _cart.ApplyCoupon("");
    }

    [TestMethod]
    public void ApplyCoupon_TotalDoesNotGoBelowZero()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 1.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() >= 0m,
            "Total should never be negative after applying a coupon.");
    }

    // ---------------------------------------------------------------
    //  Combined scenarios
    // ---------------------------------------------------------------

    [TestMethod]
    public void FullWorkflow_AddRemoveCoupon_ProducesExpectedTotal()
    {
        _cart.AddItem("WIDGET", quantity: 2, price: 25.00m);
        _cart.AddItem("GADGET", quantity: 1, price: 50.00m);
        _cart.RemoveItem("GADGET");
        _cart.ApplyCoupon("SAVE10");

        decimal total = _cart.CalculateTotal();
        Assert.IsTrue(total >= 0m && total <= 50.00m,
            $"Expected a discounted total ≤ 50.00 but got {total}.");
    }
}

