1. using Microsoft.VisualStudio.TestTools.UnitTesting;
2. using Store;
3. 
4. namespace Store.Tests;
5. 
6. [TestClass]
7. public class ShoppingCartTests
8. {
9.     private ShoppingCart _cart = null!;
10. 
11.     [TestInitialize]
12.     public void Setup()
13.     {
14.         _cart = new ShoppingCart();
15.     }
16. 
17.     // ---------------------------------------------------------------
18.     //  AddItem
19.     // ---------------------------------------------------------------
20. 
21.     [TestMethod]
22.     public void AddItem_SingleItem_IncreasesTotal()
23.     {
24.         _cart.AddItem("SKU-001", quantity: 1, price: 9.99m);
25. 
26.         Assert.AreEqual(9.99m, _cart.CalculateTotal());
27.     }
28. 
29.     [TestMethod]
30.     public void AddItem_MultipleQuantity_MultipliesPrice()
31.     {
32.         _cart.AddItem("SKU-001", quantity: 3, price: 5.00m);
33. 
34.         Assert.AreEqual(15.00m, _cart.CalculateTotal());
35.     }
36. 
37.     [TestMethod]
38.     public void AddItem_MultipleDifferentItems_SumsCorrectly()
39.     {
40.         _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
41.         _cart.AddItem("SKU-002", quantity: 2, price: 7.50m);
42. 
43.         Assert.AreEqual(25.00m, _cart.CalculateTotal());
44.     }
45. 
46.     [TestMethod]
47.     public void AddItem_SameSkuTwice_CombinesQuantities()
48.     {
49.         _cart.AddItem("SKU-001", quantity: 1, price: 5.00m);
50.         _cart.AddItem("SKU-001", quantity: 2, price: 5.00m);
51. 
52.         Assert.AreEqual(15.00m, _cart.CalculateTotal());
53.     }
54. 
55.     [TestMethod]
56.     public void AddItem_ZeroQuantity_Throws()
